class Solution {
    public int getMinSwaps(String num, int k) {
        int n = num.length();
        char[] nums = num.toCharArray();
        int swaps = 0;
        for (int i = 0; i < n - 1; i++) {
            for (int j = i + 1; j < n; j++) {
                if (nums[j] > nums[i]) {
                    swaps++;
                }
            }
        }
        return swaps;
    }
}
